722→    /// For providers that reject `role: "system"` in the messages array,
723→    /// extract all system messages from `body["messages"]`, join their
724→    /// content with `\n\n`, and place the result in `body["system"]`.
725→    ///
726→    /// Must be called on the request body **after** it is fully assembled.
727→    /// This is intentionally a single body-level mutation so call sites
728→    /// cannot forget to apply it (previously reverted by accident in #586).
729→    fn apply_top_level_system_prompt(&self, body: &mut serde_json::Value) {
730→        if !self.requires_top_level_system_prompt() {
731→            return;
732→        }
733→        let Some(messages) = body
734→            .get_mut("messages")
735→            .and_then(serde_json::Value::as_array_mut)
736→        else {
737→            return;
738→        };
739→        let mut system_parts = Vec::new();
740→        messages.retain(|msg| {
741→            if msg.get("role").and_then(serde_json::Value::as_str) == Some("system") {
742→                if let Some(content) = msg.get("content").and_then(serde_json::Value::as_str)
743→                    && !content.is_empty()
744→                {
745→                    system_parts.push(content.to_string());
746→                } else if msg.get("content").is_some() {
747→                    warn!("MiniMax system message has non-string content; it will be dropped");
748→                }
749→                return false;
750→            }
751→            true
752→        });
753→        if !system_parts.is_empty() {
754→            body["system"] = serde_json::Value::String(system_parts.join("\n\n"));
755→        }
756→    }
