758→    fn serialize_messages_for_request(&self, messages: &[ChatMessage]) -> Vec<serde_json::Value> {
759→        let needs_reasoning_content = self.requires_reasoning_content_on_tool_messages();
760→        let mut remapped_tool_call_ids = HashMap::new();
761→        let mut used_tool_call_ids = HashSet::new();
762→        let mut out = Vec::with_capacity(messages.len());
763→
764→        for message in messages {
765→            let mut value = message.to_openai_value();
766→
767→            if let Some(tool_calls) = value
768→                .get_mut("tool_calls")
769→                .and_then(serde_json::Value::as_array_mut)
770→            {
771→                for tool_call in tool_calls {
772→                    let Some(tool_call_id) =
773→                        tool_call.get("id").and_then(serde_json::Value::as_str)
774→                    else {
775→                        continue;
776→                    };
777→                    let mapped_id = assign_openai_tool_call_id(
778→                        tool_call_id,
779→                        &mut remapped_tool_call_ids,
780→                        &mut used_tool_call_ids,
781→                    );
782→                    tool_call["id"] = serde_json::Value::String(mapped_id);
783→                }
784→            } else if value.get("role").and_then(serde_json::Value::as_str) == Some("tool")
785→                && let Some(tool_call_id) = value
786→                    .get("tool_call_id")
787→                    .and_then(serde_json::Value::as_str)
788→            {
789→                let mapped_id = remapped_tool_call_ids
790→                    .get(tool_call_id)
791→                    .cloned()
792→                    .unwrap_or_else(|| {
793→                        assign_openai_tool_call_id(
794→                            tool_call_id,
795→                            &mut remapped_tool_call_ids,
796→                            &mut used_tool_call_ids,
797→                        )
798→                    });
799→                value["tool_call_id"] = serde_json::Value::String(mapped_id);
800→            }
801→
802→            if needs_reasoning_content {
803→                let is_assistant =
804→                    value.get("role").and_then(serde_json::Value::as_str) == Some("assistant");
805→                let has_tool_calls = value
806→                    .get("tool_calls")
807→                    .and_then(serde_json::Value::as_array)
808→                    .is_some_and(|calls| !calls.is_empty());
