109→/// Recursively patch schema for OpenAI strict mode compliance.
110→///
111→/// OpenAI's strict mode requires:
112→/// 1. `additionalProperties: false` on every object in the schema tree
113→/// 2. All properties must be listed in the `required` array
114→///
115→/// Properties not in the original `required` array are made nullable so the
116→/// model can send `null` for unused optional fields instead of fabricating
117→/// placeholder values.
118→///
119→/// This function recursively patches nested objects in `properties`, array
120→/// `items`, `anyOf`/`oneOf`/`allOf` variants, etc.
121→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
122→    let Some(obj) = schema.as_object_mut() else {
123→        return;
124→    };
125→
126→    // Collect originally-optional property names so we can make them nullable
127→    // AFTER recursion (otherwise changing "type":"object" to ["object","null"]
128→    // would prevent the recursive pass from recognising nested objects).
129→    let mut optional_props: Vec<String> = Vec::new();
130→
131→    // If this is an object type, apply strict mode requirements
132→    if obj.get("type").and_then(|t| t.as_str()) == Some("object") {
133→        // Add additionalProperties: false
134→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
135→
136→        // Ensure all properties are in required array.
137→        if let Some(props) = obj.get("properties").and_then(|p| p.as_object()).cloned() {
138→            let originally_required: HashSet<String> = obj
139→                .get("required")
140→                .and_then(|r| r.as_array())
141→                .map(|arr| {
142→                    arr.iter()
143→                        .filter_map(|v| v.as_str().map(String::from))
144→                        .collect()
145→                })
146→                .unwrap_or_default();
147→
148→            let all_prop_names: Vec<serde_json::Value> =
149→                props.keys().map(|k| serde_json::json!(k)).collect();
150→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));

