303→/// Convert typed chat messages to Responses API input items.
304→///
305→/// Responses API accepts a heterogeneous input array (messages, tool calls, and
306→/// tool outputs). This keeps one canonical conversion for providers that use
307→/// Responses transport (SSE or WebSocket).
308→#[must_use]
309→pub fn to_responses_input(messages: &[ChatMessage]) -> Vec<serde_json::Value> {
310→    messages
311→        .iter()
312→        .flat_map(|msg| match msg {
313→            ChatMessage::System { .. } => {
314→                // System messages are extracted into `instructions`.
315→                vec![]
316→            },
317→            ChatMessage::User { content } => {
318→                let content_blocks = match content {
319→                    UserContent::Text(t) => {
320→                        vec![serde_json::json!({"type": "input_text", "text": t})]
321→                    },
322→                    UserContent::Multimodal(parts) => parts
323→                        .iter()
324→                        .map(|p| match p {
325→                            moltis_agents::model::ContentPart::Text(t) => {
326→                                serde_json::json!({"type": "input_text", "text": t})
327→                            },
328→                            moltis_agents::model::ContentPart::Image { media_type, data } => {
329→                                let data_uri = format!("data:{media_type};base64,{data}");
330→                                serde_json::json!({
331→                                    "type": "input_image",
332→                                    "image_url": data_uri,
333→                                })
334→                            },
335→                        })
336→                        .collect(),
337→                };
338→                vec![serde_json::json!({
339→                    "role": "user",
340→                    "content": content_blocks,
341→                })]
342→            },
343→            ChatMessage::Assistant {
344→                content,
345→                tool_calls,
346→            } => {
347→                if !tool_calls.is_empty() {
348→                    let mut items: Vec<serde_json::Value> = tool_calls
349→                        .iter()
350→                        .map(|tc| {
351→                            serde_json::json!({
352→                                "type": "function_call",
353→                                "call_id": tc.id,
354→                                "name": tc.name,
355→                                "arguments": tc.arguments.to_string(),
356→                            })
357→                        })
358→                        .collect();
359→                    if let Some(text) = content
360→                        && !text.is_empty()
361→                    {
362→                        items.insert(
363→                            0,
364→                            serde_json::json!({
365→                                "type": "message",
366→                                "role": "assistant",
367→                                "content": [{"type": "output_text", "text": text}]
368→                            }),
369→                        );
370→                    }
371→                    items
372→                } else {
373→                    let text = content.as_deref().unwrap_or("");
374→                    vec![serde_json::json!({
375→                        "type": "message",
376→                        "role": "assistant",
377→                        "content": [{"type": "output_text", "text": text}]
378→                    })]
379→                }
380→            },
381→            ChatMessage::Tool {
382→                tool_call_id,
383→                content,
384→            } => {
385→                vec![serde_json::json!({
386→                    "type": "function_call_output",
387→                    "call_id": tool_call_id,
388→                    "output": content,
389→                })]
390→            },
391→        })
392→        .collect()
393→}
