  1→//! Live integration tests for the MiniMax provider.
  2→//!
  3→//! These tests hit the real MiniMax API and require `MINIMAX_API_KEY` in the
  4→//! environment. They are `#[ignore]`d by default so `cargo test` skips them.
  5→//!
  6→//! Run with:
  7→//!   cargo test --test minimax_integration -- --ignored
  8→//!
  9→//! Covers regressions for:
 10→//! - #578: system prompt not injected (silently ignored top-level `system` field)
 11→//! - #582: `null` for optional array tool parameters (`allow_tools`, `deny_tools`)
 12→//! - #592: MiniMax rejects `role: system` in messages array
 13→
 14→use std::collections::HashSet;
 15→
 16→use {
 17→    futures::StreamExt,
 18→    moltis_agents::model::{ChatMessage, LlmProvider, StreamEvent, ToolCall},
 19→    moltis_providers::openai::OpenAiProvider,
 20→    secrecy::Secret,
 21→};
 22→
 23→const MINIMAX_BASE_URL: &str = "https://api.minimax.io/v1";
 24→const TEST_MODEL: &str = "MiniMax-M2.7-highspeed";
 25→
 26→/// Known MiniMax models we catalog. Keep in sync with `MINIMAX_MODELS` in
 27→/// `crates/providers/src/lib.rs`. If this list drifts, the
 28→/// `catalog_matches_live_models` test will catch it.
 29→const KNOWN_MODELS: &[&str] = &[
 30→    "MiniMax-M2.7",
 31→    "MiniMax-M2.7-highspeed",
 32→    "MiniMax-M2.5",
 33→    "MiniMax-M2.5-highspeed",
 34→    "MiniMax-M2.1",
 35→    "MiniMax-M2.1-highspeed",
 36→    "MiniMax-M2",
 37→];
 38→
 39→fn api_key() -> Secret<String> {
 40→    let key = std::env::var("MINIMAX_API_KEY")
 41→        .expect("MINIMAX_API_KEY must be set for integration tests");
 42→    Secret::new(key)
 43→}
 44→
 45→fn provider(model: &str) -> OpenAiProvider {
 46→    OpenAiProvider::new_with_name(
 47→        api_key(),
 48→        model.to_string(),
 49→        MINIMAX_BASE_URL.to_string(),
 50→        "minimax".to_string(),
 51→    )
 52→}
 53→
 54→// ── #578 / #592: System prompt handling ──────────────────────────────────────
 55→
 56→/// Regression test for #578 and #592: system prompt must reach the model.
 57→///
 58→/// We instruct the model via system prompt to include a specific keyword
 59→/// in every response. If the keyword appears, the system prompt was delivered.
 60→#[tokio::test]
 61→#[ignore]
 62→async fn system_prompt_is_received_by_model_non_streaming() {
 63→    let p = provider(TEST_MODEL);
 64→    let keyword = "PINEAPPLE";
 65→    let messages = vec![
 66→        ChatMessage::system(format!(
 67→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
 68→        )),
 69→        ChatMessage::user("What is 2+2?"),
 70→    ];
 71→
 72→    let response = p
 73→        .complete(&messages, &[])
 74→        .await
 75→        .expect("non-streaming completion should succeed");
 76→
 77→    let text = response.text.expect("response must contain text");
 78→    assert!(
 79→        text.contains(keyword),
 80→        "system prompt was not received by model: response = {text:?}"
 81→    );
 82→    assert!(response.usage.input_tokens > 0, "should report input tokens");
 83→    assert!(
 84→        response.usage.output_tokens > 0,
 85→        "should report output tokens"
 86→    );
 87→}
 88→
 89→/// Streaming variant of the system prompt test.
 90→#[tokio::test]
 91→#[ignore]
 92→async fn system_prompt_is_received_by_model_streaming() {
 93→    let p = provider(TEST_MODEL);
 94→    let keyword = "COCONUT";
 95→    let messages = vec![
 96→        ChatMessage::system(format!(
 97→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
 98→        )),
 99→        ChatMessage::user("What is 3+3?"),
100→    ];
101→
102→    let mut stream = p.stream_with_tools(messages, vec![]);
103→    let mut full_text = String::new();
104→    let mut saw_done = false;
105→
106→    while let Some(event) = stream.next().await {
107→        match event {
108→            StreamEvent::Delta(chunk) => full_text.push_str(&chunk),
109→            StreamEvent::Done(usage) => {
110→                saw_done = true;
111→                assert!(usage.input_tokens > 0, "should report input tokens");
112→                assert!(usage.output_tokens > 0, "should report output tokens");
113→                break;
114→            },
115→            StreamEvent::Error(err) => panic!("stream error: {err}"),
116→            _ => {},
117→        }
118→    }
119→
120→    assert!(saw_done, "stream must emit Done event");
121→    assert!(
122→        full_text.contains(keyword),
123→        "system prompt was not received by model: response = {full_text:?}"
124→    );
125→}
126→
127→/// Multiple system messages should all be delivered.
128→#[tokio::test]
129→#[ignore]
130→async fn multiple_system_messages_all_delivered() {
131→    let p = provider(TEST_MODEL);
132→    let messages = vec![
133→        ChatMessage::system(
134→            "You MUST include the exact word \"ZEBRA\" in every response.",
135→        ),
136→        ChatMessage::user("Tell me about computers."),
137→        ChatMessage::system(
138→            "You MUST also include the exact word \"GIRAFFE\" in every response.",
139→        ),
140→    ];
141→
142→    let response = p
143→        .complete(&messages, &[])
144→        .await
145→        .expect("completion should succeed");
146→
147→    let text = response.text.expect("response must contain text");
148→    assert!(
149→        text.contains("ZEBRA"),
150→        "first system prompt missing: {text:?}"
151→    );
152→    assert!(
153→        text.contains("GIRAFFE"),
154→        "second system prompt missing: {text:?}"
155→    );
156→}
157→
158→// ── #582: Tool calls with null optional params ───────────────────────────────
159→
160→/// The model must be able to call a tool successfully.
161→/// MiniMax models sometimes send `null` for optional array parameters;
162→/// this validates the round-trip works.
163→#[tokio::test]
164→#[ignore]
165→async fn tool_call_round_trip_non_streaming() {
166→    let p = provider(TEST_MODEL);
167→    let tools = vec![serde_json::json!({
168→        "type": "function",
169→        "function": {
170→            "name": "get_weather",
171→            "description": "Get current weather for a location",
172→            "parameters": {
173→                "type": "object",
174→                "properties": {
175→                    "location": {
176→                        "type": "string",
177→                        "description": "City name"
178→                    },
179→                    "units": {
180→                        "type": "string",
181→                        "enum": ["celsius", "fahrenheit"],
182→                        "description": "Temperature units"
183→                    }
184→                },
185→                "required": ["location"]
186→            }
187→        }
188→    })];
189→
190→    let messages = vec![ChatMessage::user(
191→        "What's the weather like in Tokyo? Use the get_weather tool.",
192→    )];
193→
194→    let response = p
195→        .complete(&messages, &tools)
196→        .await
197→        .expect("completion with tools should succeed");
198→
199→    assert!(
200→        !response.tool_calls.is_empty(),
201→        "model should call the get_weather tool, got text: {:?}",
202→        response.text
203→    );
204→
205→    let tool_call = &response.tool_calls[0];
206→    assert_eq!(tool_call.name, "get_weather");
207→    let args: serde_json::Value =
208→        serde_json::from_value(tool_call.arguments.clone()).expect("valid JSON arguments");
209→    assert!(
210→        args.get("location").is_some(),
211→        "tool call should include location"
212→    );
213→}
214→
215→/// Streaming variant: model calls a tool and we get proper streaming events.
216→#[tokio::test]
217→#[ignore]
218→async fn tool_call_round_trip_streaming() {
219→    let p = provider(TEST_MODEL);
220→    let tools = vec![serde_json::json!({
221→        "type": "function",
222→        "function": {
223→            "name": "get_weather",
224→            "description": "Get current weather for a location",
225→            "parameters": {
226→                "type": "object",
227→                "properties": {
228→                    "location": {
229→                        "type": "string",
230→                        "description": "City name"
231→                    }
232→                },
233→                "required": ["location"]
234→            }
235→        }
236→    })];
237→
238→    let messages = vec![ChatMessage::user(
239→        "What's the weather in Paris? Use the get_weather tool.",
240→    )];
241→
242→    let mut stream = p.stream_with_tools(messages, tools);
243→    let mut saw_tool_start = false;
244→    let mut saw_done = false;
245→    let mut tool_name = String::new();
246→
247→    while let Some(event) = stream.next().await {
248→        match event {
249→            StreamEvent::ToolCallStart { name, .. } => {
250→                saw_tool_start = true;
251→                tool_name = name;
252→            },
253→            StreamEvent::Done(_) => {
254→                saw_done = true;
255→                break;
256→            },
257→            StreamEvent::Error(err) => panic!("stream error: {err}"),
258→            _ => {},
259→        }
260→    }
261→
262→    assert!(saw_done, "stream must emit Done event");
263→    assert!(saw_tool_start, "stream should include a tool call");
264→    assert_eq!(tool_name, "get_weather");
265→}
266→
267→/// Tool call with optional array params that might be null.
268→/// Regression for #582: spawn_agent-like schema with optional arrays.
269→#[tokio::test]
270→#[ignore]
271→async fn tool_call_with_optional_array_params() {
272→    let p = provider(TEST_MODEL);
273→    let tools = vec![serde_json::json!({
274→        "type": "function",
275→        "function": {
276→            "name": "spawn_agent",
277→            "description": "Spawn a sub-agent to perform a task",
278→            "parameters": {
279→                "type": "object",
280→                "properties": {
281→                    "task": {
282→                        "type": "string",
283→                        "description": "Task description"
284→                    },
285→                    "allow_tools": {
286→                        "type": "array",
287→                        "items": { "type": "string" },
288→                        "description": "Optional whitelist of tool names"
289→                    },
290→                    "deny_tools": {
291→                        "type": "array",
292→                        "items": { "type": "string" },
293→                        "description": "Optional blacklist of tool names"
294→                    }
295→                },
296→                "required": ["task"]
297→            }
298→        }
299→    })];
300→
301→    let messages = vec![ChatMessage::user(
302→        "Use spawn_agent to analyze the current directory. Set the task to 'list files'.",
303→    )];
304→
305→    let response = p
306→        .complete(&messages, &tools)
307→        .await
308→        .expect("completion should succeed");
309→
310→    assert!(
311→        !response.tool_calls.is_empty(),
312→        "model should call spawn_agent"
313→    );
314→
315→    let tool_call = &response.tool_calls[0];
316→    assert_eq!(tool_call.name, "spawn_agent");
317→    let args: serde_json::Value =
318→        serde_json::from_value(tool_call.arguments.clone()).expect("valid JSON arguments");
319→    assert!(args.get("task").is_some(), "must include task parameter");
320→
321→    // Validate that null optional arrays are handled gracefully
322→    // (this exercises the same code path as string_array_param)
323→    let allow = args.get("allow_tools");
324→    let deny = args.get("deny_tools");
325→
326→    // Model may send null, [], or omit entirely — all must be acceptable
327→    if let Some(val) = allow {
328→        assert!(
329→            val.is_null() || val.is_array(),
330→            "allow_tools must be null or array, got: {val}"
331→        );
332→    }
333→    if let Some(val) = deny {
334→        assert!(
335→            val.is_null() || val.is_array(),
336→            "deny_tools must be null or array, got: {val}"
337→        );
338→    }
339→}
340→
341→/// Multi-turn tool use: model calls tool, receives result, responds.
342→#[tokio::test]
343→#[ignore]
344→async fn multi_turn_tool_use() {
345→    let p = provider(TEST_MODEL);
346→    let tools = vec![serde_json::json!({
347→        "type": "function",
348→        "function": {
349→            "name": "get_weather",
350→            "description": "Get current weather for a location",
351→            "parameters": {
352→                "type": "object",
353→                "properties": {
354→                    "location": {
355→                        "type": "string",
356→                        "description": "City name"
357→                    }
358→                },
359→                "required": ["location"]
360→            }
361→        }
362→    })];
363→
364→    // Step 1: model should call the tool
365→    let messages = vec![ChatMessage::user(
366→        "What's the weather in London? Use get_weather.",
367→    )];
368→    let response = p
369→        .complete(&messages, &tools)
370→        .await
371→        .expect("first turn should succeed");
372→
373→    assert!(!response.tool_calls.is_empty(), "should call get_weather");
374→    let tc = &response.tool_calls[0];
375→
376→    // Step 2: provide tool result, model should produce a text response
377→    let messages = vec![
378→        ChatMessage::user("What's the weather in London? Use get_weather."),
379→        ChatMessage::assistant_with_tools(response.text.clone(), vec![ToolCall {
380→            id: tc.id.clone(),
381→            name: tc.name.clone(),
382→            arguments: tc.arguments.clone(),
383→        }]),
384→        ChatMessage::tool(&tc.id, r#"{"temperature": 15, "condition": "cloudy"}"#),
385→    ];
386→
387→    let final_response = p
388→        .complete(&messages, &tools)
389→        .await
390→        .expect("second turn should succeed");
391→
392→    let text = final_response.text.expect("should have text response");
393→    assert!(!text.is_empty(), "final response should not be empty");
394→}
395→
396→// ── Probe ────────────────────────────────────────────────────────────────────
397→
398→/// Provider probe must succeed against the live API.
399→#[tokio::test]
400→#[ignore]
401→async fn probe_succeeds() {
402→    let p = provider(TEST_MODEL);
403→    p.probe().await.expect("probe should succeed against live MiniMax API");
404→}
405→
406→// ── Streaming edge cases ─────────────────────────────────────────────────────
407→
408→/// Stream must emit at least one Delta and a terminal Done event.
409→#[tokio::test]
410→#[ignore]
411→async fn stream_emits_delta_and_done() {
412→    let p = provider(TEST_MODEL);
413→    let messages = vec![ChatMessage::user("Say hello in one word.")];
414→    let mut stream = p.stream(messages);
415→
416→    let mut saw_delta = false;
417→    let mut saw_done = false;
418→
419→    while let Some(event) = stream.next().await {
420→        match event {
421→            StreamEvent::Delta(_) => saw_delta = true,
422→            StreamEvent::Done(_) => {
423→                saw_done = true;
424→                break;
425→            },
426→            StreamEvent::Error(err) => panic!("stream error: {err}"),
427→            _ => {},
428→        }
429→    }
430→
431→    assert!(saw_delta, "stream must emit at least one Delta");
432→    assert!(saw_done, "stream must emit Done");
433→}
434→
435→// ── Model catalog validation ─────────────────────────────────────────────────
436→
437→/// Probe each model in our catalog and report which ones are alive.
438→/// Fails if any model that used to work no longer does, or if we detect
439→/// new models that aren't in the catalog.
440→#[tokio::test]
441→#[ignore]
442→async fn catalog_models_are_live() {
443→    let mut alive = Vec::new();
444→    let mut dead = Vec::new();
445→
446→    for &model_id in KNOWN_MODELS {
447→        let p = provider(model_id);
448→        match p.probe().await {
449→            Ok(()) => alive.push(model_id),
450→            Err(e) => dead.push((model_id, e.to_string())),
451→        }
452→    }
453→
454→    // Report results
455→    eprintln!("\n=== MiniMax Model Catalog Health ===");
456→    eprintln!("Alive ({}):", alive.len());
457→    for m in &alive {
458→        eprintln!("  ✓ {m}");
459→    }
460→    if !dead.is_empty() {
461→        eprintln!("Dead ({}):", dead.len());
462→        for (m, err) in &dead {
463→            eprintln!("  ✗ {m}: {err}");
464→        }
465→    }
466→    eprintln!("===================================\n");
467→
468→    // At least the test model must be alive
469→    assert!(
470→        alive.contains(&TEST_MODEL),
471→        "{TEST_MODEL} should be reachable"
472→    );
473→
474→    // Fail if more than half the catalog is dead — something is wrong
475→    assert!(
476→        dead.len() <= KNOWN_MODELS.len() / 2,
477→        "too many catalog models are dead: {dead:?}"
478→    );
479→}
480→
481→/// Try to discover if MiniMax has added new model patterns we don't know about.
482→///
483→/// This checks a set of speculative model names (next version bumps) and
484→/// reports any that respond successfully, so we can update the catalog.
485→#[tokio::test]
486→#[ignore]
487→async fn detect_new_models() {
488→    // Speculative names: next major/minor versions and variants
489→    let candidates = [
490→        "MiniMax-M3",
491→        "MiniMax-M3-highspeed",
492→        "MiniMax-M2.8",
493→        "MiniMax-M2.8-highspeed",
494→        "MiniMax-M2.9",
495→        "MiniMax-M2.9-highspeed",
496→        "MiniMax-M3.0",
497→        "MiniMax-M3.0-highspeed",
498→        "MiniMax-M2.7-turbo",
499→        "MiniMax-M2.7-pro",
500→        "MiniMax-M2.7-lite",
501→    ];
502→
503→    let known: HashSet<&str> = KNOWN_MODELS.iter().copied().collect();
504→    let mut discovered = Vec::new();
505→
506→    for &candidate in &candidates {
507→        if known.contains(candidate) {
508→            continue;
509→        }
510→        let p = provider(candidate);
511→        if p.probe().await.is_ok() {
512→            discovered.push(candidate);
513→        }
514→    }
515→
516→    if !discovered.is_empty() {
517→        eprintln!("\n=== NEW MiniMax Models Discovered ===");
518→        for m in &discovered {
519→            eprintln!("  → {m}");
520→        }
521→        eprintln!("Update MINIMAX_MODELS in crates/providers/src/lib.rs");
522→        eprintln!("=====================================\n");
523→    }
524→
525→    // This is informational — we don't fail on new models, just report them.
526→    // Uncomment to make this a hard failure:
527→    // assert!(discovered.is_empty(), "new MiniMax models found: {discovered:?}");
