/// Streaming variant: model calls a tool and we get proper streaming events.
#[tokio::test]
#[ignore]
async fn tool_call_round_trip_streaming() {
    let p = provider(TEST_MODEL);
    let tools = vec![serde_json::json!({
        "type": "function",
