/// Multi-turn tool use via streaming: model calls tool, receives result, responds.
/// Moonshot requires `reasoning_content` on assistant messages with tool calls,
/// so we use streaming for the first turn to capture reasoning content. The
/// serialization layer (`serialize_messages_for_request`) adds empty
/// `reasoning_content` fields to replayed assistant messages, which satisfies
/// Moonshot's API validation.
#[tokio::test]
#[ignore]
async fn multi_turn_tool_use_streaming() {
    let p = make_provider(TEST_MODEL);
    let tools = vec![weather_tool()];

    // Step 1: use streaming to get the tool call
    let messages = vec![ChatMessage::user(
        "What's the weather in London? You must use the get_weather tool.",
    )];
    let mut stream = p.stream_with_tools(messages, tools.clone());

    let mut tool_calls: Vec<(String, String, String)> = Vec::new(); // (id, name, args)
    let mut current_tool_args = String::new();
    let mut current_tool_id = String::new();
    let mut current_tool_name = String::new();

    while let Some(event) = stream.next().await {
        match event {
            StreamEvent::ToolCallStart { id, name, .. } => {
                current_tool_id = id;
                current_tool_name = name;
                current_tool_args.clear();
            },
            StreamEvent::ToolCallArgumentsDelta { delta, .. } => {
                current_tool_args.push_str(&delta);
            },
            StreamEvent::ToolCallComplete { .. } => {
                tool_calls.push((
                    current_tool_id.clone(),
                    current_tool_name.clone(),
                    current_tool_args.clone(),
                ));
            },
            StreamEvent::Done(_) => break,
            StreamEvent::Error(err) => panic!("stream error: {err}"),
            _ => {},
        }
    }
    drop(stream);

    assert!(!tool_calls.is_empty(), "should call get_weather");
    let (tc_id, tc_name, tc_args) = &tool_calls[0];
    assert_eq!(tc_name, "get_weather");

    let args: serde_json::Value = serde_json::from_str(tc_args).expect("valid JSON arguments");

    // Step 2: provide tool result via non-streaming, model should respond with text.
    // serialize_messages_for_request adds reasoning_content to assistant messages
    // for Moonshot providers.
    let messages = vec![
        ChatMessage::user("What's the weather in London? You must use the get_weather tool."),
        ChatMessage::assistant_with_tools(None, vec![ToolCall {
            id: tc_id.clone(),
            name: tc_name.clone(),
            arguments: args,
        }]),
        ChatMessage::tool(tc_id, r#"{"temperature": 15, "condition": "cloudy"}"#),
    ];

    let final_response = p
        .complete(&messages, &tools)
        .await
        .expect("second turn should succeed (reasoning_content injected by serialization)");

    let text = final_response.text.expect("should have text response");
    assert!(!text.is_empty(), "final response should not be empty");
}

